window.getImageUrl = function(path) {
  if (!path) return "";
  // Se estiver no cache de Data URI (iframe sandboxed ou offline absoluto), retorna imediatamente
  if (window.IMAGE_CACHE && window.IMAGE_CACHE[path]) {
    return window.IMAGE_CACHE[path];
  }
  return path;
};

window.handleImageError = function(imgElement, category = "portrait") {
  if (!imgElement) return;
  const orig = imgElement.getAttribute("data-orig-src") || imgElement.getAttribute("src");
  if (orig && window.IMAGE_CACHE && window.IMAGE_CACHE[orig]) {
    imgElement.src = window.IMAGE_CACHE[orig];
    return;
  }
  let fallbackSvg = 'data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 200 200" fill="%231e2532"><rect width="200" height="200" rx="8" fill="%23202532"/><circle cx="100" cy="85" r="40" fill="%23c5a059" opacity="0.3"/><path d="M50,170 C50,130 150,130 150,170 Z" fill="%23c5a059" opacity="0.3"/><text x="100" y="190" text-anchor="middle" fill="%23c5a059" font-family="serif" font-size="12">Aethelgard</text></svg>';
  if (category === "dragon" || category === "creature") {
    fallbackSvg = 'data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 200 200" fill="%23181b22"><rect width="200" height="200" rx="8" fill="%23202532"/><path d="M100,30 L130,90 L180,100 L140,140 L155,190 L100,160 L45,190 L60,140 L20,100 L70,90 Z" fill="%23ea580c" opacity="0.4"/><text x="100" y="185" text-anchor="middle" fill="%23facc15" font-family="serif" font-size="12">Criatura</text></svg>';
  } else if (category === "guild" || category === "crest") {
    fallbackSvg = 'data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 200 200" fill="%23151820"><rect width="200" height="200" rx="8" fill="%23202532"/><polygon points="100,30 160,80 140,160 60,160 40,80" fill="%23d97706" opacity="0.35"/><text x="100" y="110" text-anchor="middle" fill="%23facc15" font-family="serif" font-size="20">◈</text></svg>';
  }
  imgElement.src = fallbackSvg;
};
